190: export function createTestEntity<T extends Entity>(
191: 	typeRef: TypeRef<T>,
192: 	values?: Partial<T>,
193: 	opts?: {
194: 		populateAggregates: boolean
195: 	},
196: ): T {
197: 	const typeModel = resolveTypeReference(typeRef as TypeRef<any>)
198: 	const entity = create(typeModel, typeRef, getDefaultTestValue)
199: 	if (opts?.populateAggregates) {
200: 		for (const [_, assocDef] of typedEntries(typeModel.associations)) {
201: 			if (assocDef.cardinality === Cardinality.One) {
202: 				const assocName = assocDef.name
203: 				switch (assocDef.type) {
204: 					case "AGGREGATION": {
205: 						const assocTypeRef = new TypeRef<Entity>(assocDef.dependency ?? typeRef.app, assocDef.refTypeId)
206: 						entity[assocName] = createTestEntity(assocTypeRef, undefined, opts)
207: 						break
208: 					}
209: 					case "ELEMENT_ASSOCIATION":
210: 						entity[assocName] = `elementAssoc_${assocName}`
211: 						break
212: 					case "LIST_ASSOCIATION":
213: 						entity[assocName] = `listAssoc_${assocName}`
214: 						break
215: 					case "LIST_ELEMENT_ASSOCIATION_GENERATED":
216: 					case "LIST_ELEMENT_ASSOCIATION_CUSTOM":
217: 						entity[assocName] = [`listElemAssocList_${assocName}`, `listElemAssocElem_${assocName}`]
218: 						break
219: 					case "BLOB_ELEMENT_ASSOCIATION":
220: 						entity[assocName] = [`blobElemAssocList_${assocName}`, `blobElemAssocElem_${assocName}`]
221: 						break
222: 				}
223: 			}
224: 		}
225: 	}
226: 	if (values) {
227: 		return Object.assign(entity, values)
228: 	} else {
229: 		return entity
