				"mailDetailsListId",
				["mailDetailsElementId"],
				matchers.anything(), // ownerEncSessionKeyProvider
			),
		).thenDo(async (typeRef, listId, elementIds, keyProvider) => {
			// Simulate what EntityRestClient does:
			// It calls the key provider to get the session key for decryption

			if (keyProvider) {
				const providedKey = await keyProvider("mailDetailsElementId", mailDetailsBlob as any)

				// The provider returns the WRONG key (mail's key instead of mail details' key)
				// This causes decryption to fail because the wrong key was used

